mapper.select:
SELECT c.id AS collectionId, c.title AS collectionTitle, SUM(CASE WHEN DATE(r.submit_time) = CURDATE() THEN 1 ELSE 0 END) AS todayCount, SUM(CASE WHEN DATE(r.submit_time) = DATE_SUB(CURDATE(), INTERVAL 1 DAY) THEN 1 ELSE 0 END) AS yesterdayCount, SUM(CASE WHEN r.submit_time >= DATE_SUB(CURDATE(), INTERVAL 7 DAY) THEN 1 ELSE 0 END) AS last7DaysCount, COUNT(r.id) AS totalSubmitCount, COUNT(DISTINCT r.openid) AS totalParticipantCount FROM collection_info c LEFT JOIN registration_record r ON c.id = r.collection_id
c.enterprise_code = #{enterpriseCode}
r.share_user_id = #{userId}
GROUP BY c.id, c.title

SELECT c.id AS collectionId, c.title AS collectionTitle, SUM(CASE WHEN DATE(r.submit_time) = CURDATE() THEN 1 ELSE 0 END) AS todayCount, SUM(CASE WHEN DATE(r.submit_time) = DATE_SUB(CURDATE(), INTERVAL 1 DAY) THEN 1 ELSE 0 END) AS yesterdayCount, SUM(CASE WHEN r.submit_time >= DATE_SUB(CURDATE(), INTERVAL 7 DAY) THEN 1 ELSE 0 END) AS last7DaysCount, COUNT(r.id) AS totalSubmitCount, COUNT(DISTINCT r.openid) AS totalParticipantCount FROM collection_info c LEFT JOIN registration_record r ON c.id = r.collection_id WHERE c.id = #{collectionId}
AND r.share_user_id = #{userId}
GROUP BY c.id, c.title

SELECT DATE_FORMAT(r.submit_time, '%Y-%m-%d') AS submitDate, COUNT(r.id) AS count FROM registration_record r WHERE r.collection_id = #{collectionId} AND r.submit_time >= CONCAT(#{startDate}, ' 00:00:00') AND r.submit_time <= CONCAT(#{endDate}, ' 23:59:59')
AND r.share_user_id = #{userId}
GROUP BY DATE_FORMAT(r.submit_time, '%Y-%m-%d') ORDER BY submitDate ASC
